service: vehicle-api
provider:
  name: aws
  runtime: nodejs18.x
  region: ap-south-1
  environment:
    PG_USER: ${env:PG_USER}
    PG_PASSWORD: ${env:PG_PASSWORD}
    PG_DATABASE: ${env:PG_DATABASE}
    PG_HOST: ${env:PG_HOST}
    PG_PORT: ${env:PG_PORT}
    PG_SSL: ${env:PG_SSL}
    MONGO_URI: ${env:MONGO_URI}
    ULIP_DRIVER_DATA_URL: ${env:ULIP_DRIVER_DATA_URL}
    ULIP_FASTAG_DATA_URL: ${env:ULIP_FASTAG_DATA_URL}
    ULIP_USERNAME: ${env:ULIP_USERNAME}
    ULIP_PASSWORD: ${env:ULIP_PASSWORD}
    ULIP_CLIENT_ID: ${env:ULIP_CLIENT_ID}
    ULIP_CLIENT_SECRET: ${env:ULIP_CLIENT_SECRET}
    EMAIL_ENCRYPTION_KEY: ${env:EMAIL_ENCRYPTION_KEY}
functions:
  getVehicleByNumber:
    handler: lambda/handlers/getVehicleByNumber.handler
    events:
      - http:
          path: getulipdata/getVehicleByNumber
          method: get
  vehiclertodata:
    handler: lambda/handlers/vehiclertodata.handler
    events:
      - http:
          path: vehiclertodata/{vehicle_number}
          method: get
  adminData:
    handler: lambda/handlers/adminData.handler
    events:
      - http:
          path: admindata/{admin_id}
          method: get
  clientData:
    handler: lambda/handlers/clientData.handler
    events:
      - http:
          path: clientdata/{client_id}
          method: get
